                                  const at::Tensor& w,
                                  const at::Tensor& bias) {
    TORCH_CHECK(x.dim() == 2, \"x must be 2D\");
    TORCH_CHECK(w.dim() == 2, \"w must be 2D\");
    TORCH_CHECK(bias.dim() == 1, \"bias must be 1D\");

